INSERT INTO "public"."articles" ("id", "article_id", "media_id", "sub_media", "url", "title", "date_time", "authors", "paywall", "category", "preview_url", "body", "created_at") VALUES
	(77, 8415554, 1, NULL, 'https://www.postimees.ee/8415554/endise-korge-politseiametniku-osaline-suudimoistmine-joustus', 'Endise kõrge politseiametniku osaline süüdimõistmine jõustus', '2026-02-13 10:28:38+00', '{Postimees}', false, NULL, '//f10.pmo.ee/j4NwxLnvj7lT5Qe6_XA2xd8TwbE=/721x0/filters:focal(2270x681:3139x1408):format(webp)/nginx/o/2025/01/10/16588928t1hc10d.jpg', 'Riigikohtu otsusega jõustus Kaupo Martihhini süüditunnistamine riigisaladusega seotud kuritegudes ja äriühingu vara omastamises ning õigeksmõistmine kelmuses PPA vastu, kuid kõige mahukamat majanduskuriteo süüdistust peab ringkonnakohus uuesti arutama.

Riigikohtus olid arutusel politsei- ja piirivalveameti (PPA) Lõuna sisekontrollitalituse endisele juhile Kaupo Martihhinile esitatud süüdistused, mis puudutasid Tartekplus AS-i vara omastamist ja usalduse kuritarvitamist, riigisaladuse avalikustamist, kaitsepolitseiametile (KAPO) valeandmete esitamist ning kelmust PPA vastu.', '2026-02-13 15:16:01.144005+00'),
	(78, 8415551, 1, 'arvamus', 'https://arvamus.postimees.ee/8415551/mattias-joesaar-ideed-mis-maetakse-uuringute-kalmistule', 'MATTIAS JÕESAAR ⟩ Ideed, mis maetakse uuringute kalmistule', '2026-02-13 13:00:00+00', '{"Mattias Jõesaar"}', true, NULL, '//f12.pmo.ee/dEFOLqcQSYJ-82db-_-c-6WkxEs=/721x0/filters:focal(361x220:1682x1321):format(webp)/nginx/o/2021/11/04/14183275t1he729.jpg', 'Värskelt avaldatud inimarengu aruanne suutis täpselt sõnastada universaalse tõdemuse, et avalikus sektoris kipub uuringust saama lahenduse asendus, mitte lahenduse algus. Ressurss kulub eesmärgipäratutele uuringutele ja projektidele, kuid olulisi poliitilisi otsuseid kiputakse vastu võtma isegi ilma mõjuanalüüsita, kirjutab arvamustoimetaja Mattias Jõesaar.

Inimarengu aruande peatoimetaja Eneli Kindsiko ütles, et viimase kümne aasta jooksul on Eestis üksnes hariduse kohta kirjutatud vähemalt 420 000 lehekülge analüüse ja uuringuid. Nendest uuringutest enamasti mitte midagi ei saa. Uuringu valmimine justkui olekski tulemus.', '2026-02-13 15:16:02.474785+00'),
	(79, 8415550, 1, 'rus', 'https://rus.postimees.ee/8415550/rayner-saks-ukraina-atakovala-rossiyskie-sklady-boepripasov-raketami-flamingo', 'РАЙНЕР САКС ⟩ Украина атаковала российские склады боеприпасов ракетами «Фламинго»', '2026-02-13 10:47:21+00', '{"Райнер Сакс"}', false, NULL, '//f7.pmo.ee/N8QFD_HjdLVuzZ7QKvZaNFzqu3w=/721x0/filters:focal(262x359:951x1071):format(webp)/nginx/o/2025/10/13/17208466t1hf5ad.jpg', 'Подтвердилась информация о том, что вчера украинская армия атаковала ракетами «Фламинго» арсенал с ракетами и другими боеприпасами в Волгоградской области, пишет эксперт по безопасности Райнер Сакс.

В опубликованном вчера в социальных сетях видеоклипе виден запуск шести ракет, которыми, как утверждается, и был атакован этот арсенал. Постепенно использование этих ракет становится все более частым и эффективным.

Губернатор Волгоградской области России также сообщил сегодня ночью об атаках дронов и пожаре на промышленных предприятиях, который, по его словам, был вызван обломками сбитых силами ПВО беспилотников. Российским чиновникам запрещено говорить о прямых попаданиях дронов или ракет. Поэтому об ущербе от атак сообщается как об успешном результате работы ПВО.

По оценке одного украинского военного в отставке, украинские войска смогли ликвидировать ПВО российской армии на волгоградском направлении, и поэтому в последние дни в этом секторе было больше атак. Украинские подразделения беспилотников каждую неделю публикуют доказательства уничтожения как минимум двух мобильных систем ПВО российской армии, а это значит, что в конечном итоге эти атаки должны сказаться и на российской противовоздушной обороне.

У России никогда не хватало средств ПВО для защиты всей своей территории. Атаки украинских беспилотников показали, что если удается прорвать оборону, сосредоточенную у украинской границы, то эффективная защита остается лишь в немногих стратегически важных регионах России.

Президент Украины в интервью изданию The Atlantic заявил, что Украина готова продолжать воевать с Россией, если потребуется. По словам президента, лучше воевать, чем заключать плохой договор. Еще две недели назад президент Украины не позволил бы себе публично такого высказывания.

Европейский союз завершает процесс выделения Украине 90 миллиардов кредитных средств. После последней встречи сторонников Украины в так называемом формате «Рамштайн» говорят о пакете военной помощи Украине в размере 35 миллиардов в этом году. Речь идет об обещаниях стран, участвующих в этом формате. Даже если их не удастся выполнить в полном объеме, у Украины в перспективе на этот год будет достаточно денег, чтобы организовать сопротивление.

Международные финансовые и экономические аналитики прогнозируют России серьезные экономические трудности начиная с весны или лета этого года. Уже в прошлом году началось более быстрое падение нефтяных доходов России, которое усиливалось из месяца в месяц, и аналитики говорят в первую очередь о грядущем финансовом кризисе. Таким образом, в стратегическом плане ситуация в информационном пространстве для Украины значительно лучше по сравнению с прошлым годом, а поле для маневра у президента Украины в дипломатическом процессе стало немного шире.

Украинские беспилотники атаковали нефтеперерабатывающий завод в Ухте в Республике Коми, на северо-западе России, на расстоянии 1700 км. Завод, принадлежащий компании Lukoil, перерабатывал около 4 миллионов тонн сырой нефти в год.

В результате атаки беспилотников российской армии на юге Украины на территории Одесской области возникли проблемы с электро- и водоснабжением. В результате атаки пострадали четыре человека.

На фронтах количество атак российской армии вчера несколько возросло, но в целом интенсивность атак сопоставима с предыдущими днями. Основной целью наступления российской армии по-прежнему является Покровский район на юге Донбасса.', '2026-02-13 15:16:02.69695+00'),
	(80, 8415559, 1, 'rus', 'https://rus.postimees.ee/8415559/vratar-sbornoy-latvii-po-hokkeyu-kritikuet-edu-v-olimpiyskoy-derevne-ne-znayu-kuda-uhodyat-dengi', 'Вратарь сборной Латвии по хоккею критикует еду в олимпийской деревне: не знаю, куда уходят деньги', '2026-02-13 11:05:00+00', '{rus.tvnet.lv}', true, NULL, '//f10.pmo.ee/NO6gn9-jC7L3vIOfz3myJKiYJvM=/721x0/filters:focal(2940x569:4806x2774):format(webp)/nginx/o/2025/11/27/17302073t1h6316.jpg', 'Итальянская кухня известна во всем мире. Немало путешественников выбирают Италию как направление кулинарного туризма, потому что там действительно есть что попробовать - особенно пиццу, пасту, джелато и, конечно, тирамису. Но так ли хороша еда в столовых олимпийских деревень?

Вратарь сборной Латвии по хоккею Артур Шилов в разговоре с TVNET+ довольно жестко высказывается о доступности и качестве еды в олимпийской деревне Милана.', '2026-02-13 15:16:03.274883+00'),
	(81, 8415564, 1, 'rus', 'https://rus.postimees.ee/8415564/eks-glavu-vnutrennego-kontrolya-ppa-priznali-vinovnym-v-razglashenii-gostayny-i-prisvoenii-imushchestva', 'Экс-главу внутреннего контроля PPA признали виновным в разглашении гостайны и присвоении имущества', '2026-02-13 11:05:05+00', '{rus.postimees.ee}', false, NULL, '//f11.pmo.ee/y8HAK_fdC9dEAEw4yW-L8WoF8ww=/721x0/filters:focal(271x508:792x632):format(webp)/nginx/o/2025/12/11/17333420t1hfae1.jpg', 'Бывший руководитель внутреннего контроля PPA Каупо Мардихин признан виновным в разглашении гостайны и присвоении имущества, но оправдан по эпизоду мошенничества с командировочными.

Решением Государственного суда вступил в силу обвинительный приговор в отношении Каупо Мардихина по эпизодам, связанным с государственной тайной и присвоением имущества предприятия, а также оправдание по обвинению в мошенничестве в отношении Департамента полиции и погранохраны (PPA). В то же время самое объемное экономическое обвинение окружной суд должен рассмотреть заново.

В Государственном суде рассматривалось дело бывшего руководителя Лыунаского отдела внутреннего контроля Департамента полиции и погранохраны Каупо Мардихина. Ему были предъявлены обвинения в присвоении и злоупотреблении доверием в отношении имущества компании Tartekplus AS, разглашении государственной тайны, представлении ложных сведений Департаменту полиции безопасности (КаПо), а также в мошенничестве в отношении PPA.

Каупо Мардихин является мажоритарным акционером и фактическим руководителем Tartekplus AS, занимающейся средствами организации дорожного движения, пленочными работами и восстановлением номерных знаков. В 2014 году он учредил OÜ Tartek Grupp и, по версии обвинения, использовал эту фирму для вывода активов из Tartekplus.В частности, был заключен договор аренды, по которому принадлежащий Tartekplus объект недвижимости в Тарту был сдан в аренду на десять лет Tartek Grupp на крайне выгодных условиях. Кроме того, Tartek Grupp получала деньги за работы, фактически выполненные Tartekplus.

Уездный суд признал Мардихина виновным в присвоении, но окружной суд переквалифицировал эти действия в злоупотребление доверием. Государственный суд отменил решение окружного суда в этой части, а также решение о взыскании более 238 000 евро как дохода, полученного преступным путем.Окружному суду предстоит заново рассмотреть эпизод злоупотребления доверием в отношении Tartekplus: в том числе вопрос о наличии умысла и размере причиненного ущерба, а также вопрос о конфискации предполагаемого криминального дохода.

В частности, окружной суд исходил из того, что из‑за договора аренды Tartekplus понесла ущерб почти на 200 000 евро, но при этом не учел, к примеру, довод защиты о том, что компания одновременно избавилась и от расходов по содержанию объекта.

В то же время Государственный суд согласился с решениями уездного и окружного судов в части эпизода с присвоением металлолома, из‑за чего Tartekplus недополучила более 15 000 евро.

Кауто Мардихин был также обвинен в том, что дал доступ для посторонних лиц к документам, содержащим государственную тайну. При обыске в офисе Tartekplus на компьютерах, внешних жестких дисках и в папке на полке было обнаружено более десяти секретных документов, связанных с деятельностью полиции, с которыми могли ознакомиться лица, пользовавшиеся помещениями.

Уездный суд признал его виновным, однако окружной оправдал, посчитав, что умысла на разглашение гостайны не было и речь идет лишь о небрежности. Государственный суд пришел к выводу, что преступление все же было совершено как минимум с косвенным умыслом.Суд отметил, что Мардихин многие годы занимал высокие должности в полиции, в том числе возглавлял внутренний контроль, и, следовательно, хорошо знал требования по работе с государственной тайной. Тем не менее, уходя из полиции, он забрал с собой и перевез в офис Tartekplus большое количество документов, не проверив, содержат ли они секретные сведения.

Государственный суд согласился с окружным судом в той части, где Мардихин признан виновным в представлении КаПо ложных сведений при продлении допуска к государственной тайне. В то же время он был оправдан по обвинению в мошенничестве, связанного с запросом примерно 2500 евро командировочных у PPA.

Отдельно в решении подробно рассмотрен вопрос ущерба, причиненного Каупо Мардихину самим уголовным процессом.

Государственный суд, в частности, отметил, что применение наручников при его задержании как подозреваемого было необоснованным. Окружной суд ранее присудил Мардихину 1000 евро компенсации за почти трехчасовое содержание в наручниках, и Государственный суд признал эту сумму релевантной.

Также в ходе расследования неоднократно нарушалось право Мардихина на адвокатскую тайну. За это Государственный суд присудил ему компенсацию в размере 1500 евро. Дополнительно ему была назначена выплата за то, что следственные органы без достаточных оснований удерживали наличные, изъятые при обыске по месту жительства, более девяти месяцев.', '2026-02-13 15:16:03.933474+00'),
	(82, 8415566, 1, 'rus', 'https://rus.postimees.ee/8415566/estonskaya-debyutantka-olimpiady-ne-sumela-proyti-dalshe-1-8-finala', 'Эстонская дебютантка Олимпиады не сумела пройти дальше 1/8 финала', '2026-02-13 14:02:03+00', '{rus.postimees.ee}', false, NULL, '//f9.pmo.ee/bXJWQqp_F0PlLxBBakd0G7vN21Y=/721x0/filters:focal(3024x243:3376x684):format(webp)/nginx/o/2026/02/13/17442305t1h8675.jpg', 'Эстонская сноубордистка Май Брит Тедер сегодня дебютировала на Олимпиаде и стала первой в истории Эстонии спортсменкой в этой дисциплине, вышедшей на Олимпийские игры. В беседе с ERR Тедер сказала, что уже достаточно освоилась с трассой и хочет показать максимально возможный заезд.

На олимпийской трассе сноуборд-кросса в Ливиньо Тедер успела сделать одиннадцать тренировочных заездов и привыкла к впечатляющему спуску. «Лично мне трасса очень нравится. Поначалу она была немного сложной, но мы сделали здесь столько спусков, что теперь все стало проще. Сейчас на тренировках уже очень здорово ехать вчетвером», - сказала она ERR.

18-летняя атлетка рассказала, что старт сложнее обычного. «Старт более технический, я еще ни разу не ехала с такого большого и мощного старта. На этапах Кубка мира старт был немного полегче, но это классно!» - добавила она. «Дома я отрабатывала старт, мы построили стартовый сектор в Техванди. Но это было пару лет назад, сейчас уже особо не потренируешься. Нужно именно соревноваться, проходить разные трассы - и так приходит опыт».

Дебют в Кубке мира Тедер сделала в прошлом сезоне, ее лучшим результатом стало двадцатое место. В этом году она выступила на трех этапах Кубка мира и завоевала олимпийскую путевку. Своим козырем на первых Играх она называет виражи. «На трамплинах я тоже чувствую себя комфортно, все должно быть очень хорошо», - сказала она.

В сноуборд-кроссе сначала проводятся квалификационные заезды, в которых спортсмены проходят трассу по одному. Затем по показанному времени им присваивают стартовые номера, а борьба начинается с 1/8 финала, где в каждом заезде участвуют по четыре спортсмена. «Мое ожидание - квалифицироваться двадцать пятой, постараюсь выложиться по максимуму и показать лучший свой заезд. А там и место будет соответствующее», - сказала Тедер.

В первом заезде квалификации Тедер заняла 27 место (1.18,10) и не смогла попасть в топ-20 посева. Пришлось ехать второй заезд, который она завершила с результатом 1.18,47 и заняла десятое место в группе из двенадцати спортсменок. Таким образом, на основную гонку Тедер получила 30-й стартовый номер.

Тройка лучших в квалификации: Ева Адамчикова (Чехия; 1.12,29), Леа Каста (Франция; 1.12,79) и Ноэми Видмер (Швейцария; 1.13,12).

***

По итогам вечерних соревнований олимпийской чемпионкой стала австралийка Джози Бафф. Она опередила чешку Еву Адамчикову и итальянку Микелу Мойоли.

Эстонская спортсменка Май Брит Тедер не смогла пройти дальше 1/8 финала. В пятом заезде 1/8 финала Тедер уступила соперницам Ноэми Видмер, Майе-Ли Яфрате Даниельссон и Алин Альбрехт.', '2026-02-13 15:16:04.504274+00'),
	(83, 8415575, 1, 'arvamus', 'https://arvamus.postimees.ee/8415575/europarlamendi-liikmed-oleks-aarmiselt-valus-kui-rok-julma-tegelikkuse-ees-silmad-sulgeks', 'EUROPARLAMENDI LIIKMED ⟩ Oleks äärmiselt valus, kui ROK julma tegelikkuse ees silmad sulgeks', '2026-02-13 11:12:03+00', '{"Urmas Paet"}', true, NULL, '//f11.pmo.ee/KLiR6xeqXFnypY4rLLgtKNG29RE=/721x0/filters:focal(2328x1502:2771x1786):format(webp)/nginx/o/2026/02/11/17437883t1hf115.jpg', 'Kutsun koos kolleegidega Euroopa Parlamendist Rahvusvahelist Olümpiakomiteed tühistama Ukraina skeletonisõitja Vladõslav Heraskevõtši diskvalifitseerimist olümpiamängudelt, kirjutab europarlamendi liige Urmas Paet.

